syntax.postgresql:
-- Create a login role (user)
CREATE ROLE app_user WITH LOGIN PASSWORD 'secure_password';

-- Create a group role (no login)
CREATE ROLE readonly_group;

-- Grant privileges to the group
GRANT SELECT ON ALL TABLES IN SCHEMA public TO readonly_group;

-- Add a user to the group
GRANT readonly_group TO app_user;

-- Create a superuser
CREATE ROLE admin WITH LOGIN PASSWORD 'admin_pass' SUPERUSER;

syntax.mysql:
-- Create a user
CREATE USER 'app_user'@'%' IDENTIFIED BY 'secure_password';

-- Create a role (MySQL 8.0+)
CREATE ROLE 'readonly_role';

-- Grant privileges to the role
GRANT SELECT ON testdb.* TO 'readonly_role';

-- Assign role to user
GRANT 'readonly_role' TO 'app_user'@'%';

-- Activate the role
SET DEFAULT ROLE 'readonly_role' TO 'app_user'@'%';

syntax.mariadb:
-- Create a user
CREATE USER 'app_user'@'%' IDENTIFIED BY 'secure_password';

-- Create a role (MariaDB 10.0.5+)
CREATE ROLE readonly_role;

-- Grant privileges to the role
GRANT SELECT ON testdb.* TO readonly_role;

-- Assign role to user
GRANT readonly_role TO 'app_user'@'%';

-- Set default role
SET DEFAULT ROLE readonly_role FOR 'app_user'@'%';

syntax.postgresql:
-- Enable RLS on a table
ALTER TABLE orders ENABLE ROW LEVEL SECURITY;

-- Create a policy: users can only see their own orders
CREATE POLICY user_orders_policy ON orders
  FOR SELECT
  USING (user_id = current_setting('app.current_user_id')::INT);

-- Create a policy: users can only insert orders for themselves
CREATE POLICY user_insert_policy ON orders
  FOR INSERT
  WITH CHECK (user_id = current_setting('app.current_user_id')::INT);

-- Set the current user context
SET app.current_user_id = '42';

-- Now SELECT * FROM orders only returns orders for user 42

-- Grant SELECT on a specific table
GRANT SELECT ON users TO readonly_role;

-- Grant all privileges on a table
GRANT ALL PRIVILEGES ON orders TO app_role;

-- Grant on all tables in a schema
GRANT SELECT ON ALL TABLES IN SCHEMA public TO reporting_role;

-- Grant with the ability to re-grant
GRANT SELECT ON products TO manager_role WITH GRANT OPTION;

-- Revoke a privilege
REVOKE INSERT, UPDATE ON users FROM readonly_role;

-- Grant schema usage
GRANT USAGE ON SCHEMA public TO app_role;

syntax.mysql:
-- Grant SELECT on a specific table
GRANT SELECT ON testdb.users TO 'readonly_user'@'%';

-- Grant all privileges on a database
GRANT ALL PRIVILEGES ON testdb.* TO 'app_user'@'%';

-- Grant specific privileges
GRANT SELECT, INSERT, UPDATE ON testdb.orders TO 'app_user'@'%';

-- Grant with the ability to re-grant
GRANT SELECT ON testdb.products TO 'manager'@'%' WITH GRANT OPTION;

-- Revoke a privilege
REVOKE INSERT ON testdb.users FROM 'readonly_user'@'%';

-- Apply changes
FLUSH PRIVILEGES;

