syntax.mysql:
-- DEFINER: runs with creator's privileges (default)
DELIMITER //
CREATE DEFINER = 'admin'@'localhost'
FUNCTION get_user_email(uid INT)
RETURNS VARCHAR(100)
SQL SECURITY DEFINER
DETERMINISTIC
BEGIN
  DECLARE user_email VARCHAR(100);
  SELECT email INTO user_email FROM users WHERE id = uid;
  RETURN user_email;
END //
DELIMITER ;

-- INVOKER: runs with caller's privileges
DELIMITER //
CREATE FUNCTION search_count(keyword VARCHAR(100))
RETURNS INT
SQL SECURITY INVOKER
DETERMINISTIC
BEGIN
  DECLARE cnt INT;
  SELECT COUNT(*) INTO cnt FROM products WHERE name LIKE CONCAT('%', keyword, '%');
  RETURN cnt;
END //
DELIMITER ;

